CustomFunction.Calculation:
// Assembles and returns the full SQL string without executing it.
// Useful for debugging. Bindings are represented as ? placeholders.
// Output is pretty-printed: each major clause on its own line,
// child items (fields, conditions, columns) indented with 4 spaces.
Let
(
[
_table = JSONGetElement ( query ; "table" ) ;
_selects = JSONGetElement ( query ; "selects" ) ;
_distinct = JSONGetElement ( query ; "distinct" ) ;
_joins = JSONGetElement ( query ; "joins" ) ;
_joinCount = JSONGetElement ( query ; "joinCount" ) ;
_wheres = JSONGetElement ( query ; "wheres" ) ;
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_groupBys = JSONGetElement ( query ; "groupBys" ) ;
_groupByCount = JSONGetElement ( query ; "groupByCount" ) ;
_havings = JSONGetElement ( query ; "havings" ) ;
_havingCount = JSONGetElement ( query ; "havingCount" ) ;
_orderBys = JSONGetElement ( query ; "orderBys" ) ;
_orderByCount = JSONGetElement ( query ; "orderByCount" ) ;
_limit = JSONGetElement ( query ; "limit" ) ;
_offset = JSONGetElement ( query ; "offset" ) ;
_unions = JSONGetElement ( query ; "unions" ) ;
_unionCount = JSONGetElement ( query ; "unionCount" ) ;
_in = "    " ;
_selectKeyword = If ( not IsEmpty ( _distinct ) and _distinct ; "SELECT DISTINCT" ; "SELECT" ) ;
_selectFields = Substitute ( _selects ; ", " ; "," & ¶ & _in ) ;
_joinRaw = If ( _joinCount > 0 ; QueryBuildJoins_cf ( _joins ; _joinCount ; 0 ) ; "" ) ;
_joinSplit = Substitute ( Substitute ( Substitute ( Substitute ( _joinRaw ;
	" INNER JOIN " ; ¶ & "INNER JOIN " ) ;
	" LEFT JOIN " ; ¶ & "LEFT JOIN " ) ;
	" RIGHT JOIN " ; ¶ & "RIGHT JOIN " ) ;
	" CROSS JOIN " ; ¶ & "CROSS JOIN " ) ;
_joinClause = If ( _joinCount > 0 ;
	¶ & Substitute ( Substitute ( Substitute ( Substitute ( _joinSplit ;
		"INNER JOIN " ; "INNER JOIN" & ¶ & _in ) ;
		"LEFT JOIN " ; "LEFT JOIN" & ¶ & _in ) ;
		"RIGHT JOIN " ; "RIGHT JOIN" & ¶ & _in ) ;
		"CROSS JOIN " ; "CROSS JOIN" & ¶ & _in ) ;
	""
) ;
_whereRaw = If ( _whereCount > 0 ; QueryBuildWheres_cf ( _wheres ; _whereCount ; 0 ) ; "" ) ;
_whereClause = If ( _whereCount > 0 ;
	¶ & "WHERE" & ¶ & _in & Substitute ( Substitute ( _whereRaw ; " AND " ; ¶ & _in & "AND" & ¶ & _in ) ; " OR " ; ¶ & _in & "OR" & ¶ & _in ) ;
	""
) ;
_groupByRaw = If ( _groupByCount > 0 ; QueryBuildGroupBys_cf ( _groupBys ; _groupByCount ; 0 ) ; "" ) ;
_groupByClause = If ( _groupByCount > 0 ;
	¶ & "GROUP BY" & ¶ & _in & Substitute ( _groupByRaw ; ", " ; "," & ¶ & _in ) ;
	""
) ;
_havingRaw = If ( _havingCount > 0 ; QueryBuildHavings_cf ( _havings ; _havingCount ; 0 ) ; "" ) ;
_havingClause = If ( _havingCount > 0 ;
	¶ & "HAVING" & ¶ & _in & Substitute ( Substitute ( _havingRaw ; " AND " ; ¶ & _in & "AND" & ¶ & _in ) ; " OR " ; ¶ & _in & "OR" & ¶ & _in ) ;
	""
) ;
_orderByRaw = If ( _orderByCount > 0 ; QueryBuildOrderBys_cf ( _orderBys ; _orderByCount ; 0 ) ; "" ) ;
_orderByClause = If ( _orderByCount > 0 ;
	¶ & "ORDER BY" & ¶ & _in & Substitute ( _orderByRaw ; ", " ; "," & ¶ & _in ) ;
	""
) ;
_offsetClause = If ( not IsEmpty ( _offset ) ; ¶ & "OFFSET " & _offset & " ROWS" ; "" ) ;
_limitClause = If ( not IsEmpty ( _limit ) ; ¶ & "FETCH FIRST " & _limit & " ROWS ONLY" ; "" ) ;
_unionClause = If ( not IsEmpty ( _unionCount ) and _unionCount > 0 ;
	QueryBuildUnions_cf ( _unions ; _unionCount ; 0 ) ;
	""
)
];
_selectKeyword & ¶ & _in & _selectFields &
¶ & "FROM" & ¶ & _in & _table &
_joinClause &
_whereClause &
_groupByClause &
_havingClause &
_orderByClause &
_offsetClause &
_limitClause &
_unionClause
)
